Rule.Source:
  import sailpoint.object.AttributeAssignment;
  import sailpoint.object.Identity;
  import sailpoint.object.WorkflowCase;
  import sailpoint.api.Terminator;
  import sailpoint.tools.Util;

  private deletePendingRefreshWorkflow(Identity identity) {

    String pendingRefreshWorkflow = identity.getAttribute("pendingRefreshWorkflow");

    if (Util.isNotNullOrEmpty(pendingRefreshWorkflow)) {

      WorkflowCase workflowCase = context.getObjectByName(WorkflowCase.class, pendingRefreshWorkflow);

      if (workflowCase != null) {

        Terminator terminator = new Terminator(context);
        terminator.deleteObject(workflowCase);

      }

    }

  }

  private cleanupAttributeAssignments(Identity identity) {

    List attributeAssignments = identity.getAttributeAssignments();

    if (attributeAssignments != null && !attributeAssignments.isEmpty()) {

      Iterator aaIt = attributeAssignments.iterator();

      while (aaIt.hasNext()) {

        AttributeAssignment aa = (AttributeAssignment) aaIt.next();
        aa.setNativeIdentity(null);
        context.saveObject(identity);
        context.commitTransaction();

      }

    }

  }

  private removePendingRefreshWorkflowEntry(Identity identity) {

    String pendingRefreshWorkflow = identity.getAttribute("pendingRefreshWorkflow");

    if (Util.isNotNullOrEmpty(pendingRefreshWorkflow)) {

      WorkflowCase workflowCase = context.getObjectByName(WorkflowCase.class, pendingRefreshWorkflow);

      if (workflowCase == null) {

        identity.removeAttribute("pendingRefreshWorkflow");
        context.saveObject(identity);
        context.commitTransaction();
        
      }

    }

  }

  if (identity != null) {

    deletePendingRefreshWorkflow(identity);

    cleanupAttributeAssignments(identity);
    
    removePendingRefreshWorkflowEntry(identity);

  }
